51: func registerDashboardRoles(cfg *setting.Cfg, features featuremgmt.FeatureToggles, service accesscontrol.Service) error {
52: 	if !cfg.RBAC.PermissionsWildcardSeed("dashboard") {
53: 		return nil
54: 	}
55: 
56: 	viewer := accesscontrol.RoleRegistration{
57: 		Role: accesscontrol.RoleDTO{
58: 			Name:        "fixed:dashboards:viewer",
59: 			DisplayName: "Viewer",
60: 			Description: "View all dashboards",
61: 			Group:       "Dashboards",
62: 			Permissions: accesscontrol.PermissionsForActions(getDashboardViewActions(features), dashboards.ScopeDashboardsAll),
63: 			Hidden:      true,
64: 		},
65: 		Grants: []string{"Viewer"},
66: 	}
67: 
68: 	editor := accesscontrol.RoleRegistration{
69: 		Role: accesscontrol.RoleDTO{
70: 			Name:        "fixed:dashboards:editor",
71: 			DisplayName: "Editor",
72: 			Description: "Edit all dashboards.",
73: 			Group:       "Dashboards",
74: 			Permissions: accesscontrol.PermissionsForActions(getDashboardEditActions(features), dashboards.ScopeDashboardsAll),
75: 			Hidden:      true,
