77: 		Grants: []string{"Editor"},
78: 	}
79: 
80: 	admin := accesscontrol.RoleRegistration{
81: 		Role: accesscontrol.RoleDTO{
82: 			Name:        "fixed:dashboards:admin",
83: 			DisplayName: "Admin",
84: 			Description: "Administer all dashboards.",
85: 			Group:       "Dashboards",
