95: func ProvideDashboardPermissions(
96: 	cfg *setting.Cfg, features featuremgmt.FeatureToggles, router routing.RouteRegister, sql db.DB, ac accesscontrol.AccessControl,
97: 	license licensing.Licensing, dashboardService dashboards.DashboardService, folderService folder.Service, service accesscontrol.Service,
98: 	teamService team.Service, userService user.Service, actionSetService resourcepermissions.ActionSetService,
99: 	dashboardPermissionsRegistration dashboards.PermissionsRegistrationService,
100: ) (*DashboardPermissionsService, error) {
101: 	getDashboard := func(ctx context.Context, orgID int64, resourceID string) (*dashboards.Dashboard, error) {
102: 		query := &dashboards.GetDashboardQuery{UID: resourceID, OrgID: orgID}
103: 		queryResult, err := dashboardService.GetDashboard(ctx, query)
104: 		if err != nil {
105: 			return nil, err
106: 		}
107: 		return queryResult, nil
108: 	}
109: 
110: 	if err := registerDashboardRoles(cfg, features, service); err != nil {
111: 		return nil, err
112: 	}
113: 
114: 	options := resourcepermissions.Options{
115: 		Resource:          "dashboards",
116: 		ResourceAttribute: "uid",
117: 		ResourceValidator: func(ctx context.Context, orgID int64, resourceID string) error {
118: 			ctx, span := tracer.Start(ctx, "accesscontrol.ossaccesscontrol.ProvideDashboardPermissions.ResourceValidator")
119: 			defer span.End()
120: 
121: 			ctx, _ = identity.WithServiceIdentity(ctx, orgID)
122: 			dashboard, err := getDashboard(ctx, orgID, resourceID)
123: 			if err != nil {
124: 				return err
125: 			}
126: 
127: 			if dashboard.IsFolder {
128: 				return errors.New("not found")
129: 			}
130: 
131: 			return nil
132: 		},
133: 		InheritedScopesSolver: func(ctx context.Context, orgID int64, resourceID string) ([]string, error) {
134: 			ctx, _ = identity.WithServiceIdentity(ctx, orgID)
135: 			dashboard, err := getDashboard(ctx, orgID, resourceID)
136: 			if err != nil {
137: 				return nil, err
138: 			}
139: 
140: 			scopes := []string(accesscontrol.WildcardsFromPrefix(dashboards.ScopeFoldersPrefix))
141: 			metrics.MFolderIDsServiceCount.WithLabelValues(metrics.AccessControl).Inc()
142: 			if dashboard.FolderUID != "" {
143: 				nestedScopes, err := dashboards.GetInheritedScopes(ctx, orgID, dashboard.FolderUID, folderService)
144: 				if err != nil {
145: 					return nil, err
146: 				}
147: 
148: 				scopes = append(scopes, dashboards.ScopeFoldersProvider.GetResourceScopeUID(dashboard.FolderUID))
149: 				scopes = append(scopes, nestedScopes...)
150: 				return scopes, nil
151: 			}
152: 
153: 			return append(scopes, dashboards.ScopeFoldersProvider.GetResourceScopeUID(folder.GeneralFolderUID)), nil
154: 		},
155: 		Assignments: resourcepermissions.Assignments{
156: 			Users:           true,
157: 			Teams:           true,
158: 			BuiltInRoles:    true,
159: 			ServiceAccounts: true,
160: 		},
161: 		PermissionsToActions: map[string][]string{
162: 			"View":  getDashboardViewActions(features),
163: 			"Edit":  getDashboardEditActions(features),
164: 			"Admin": getDashboardAdminActions(features),
165: 		},
166: 		ReaderRoleName: "Permission reader",
167: 		WriterRoleName: "Permission writer",
168: 		RoleGroup:      "Dashboards",
169: 	}
170: 
171: 	srv, err := resourcepermissions.New(cfg, options, features, router, license, ac, service, sql, teamService, userService, actionSetService)
172: 	if err != nil {
173: 		return nil, err
174: 	}
175: 	s := &DashboardPermissionsService{srv}
176: 	dashboardPermissionsRegistration.RegisterDashboardPermissions(s)
177: 	return s, nil
178: }
