25: func HandleNoCacheHeaders(ctx *contextmodel.ReqContext) {
26: 	// X-Grafana-NoCache tells Grafana to skip the cache while retrieving datasource instance metadata
27: 	ctx.SkipDSCache = ctx.Req.Header.Get("X-Grafana-NoCache") == "true"
28: 	// X-Cache-Skip tells Grafana to skip the Enterprise query/resource cache while issuing query and resource calls
