32: func AddDefaultResponseHeaders(cfg *setting.Cfg) web.Handler {
33: 	t := web.NewTree()
34: 	t.Add("/api/datasources/uid/:uid/resources/*", nil)
35: 	t.Add("/api/datasources/:id/resources/*", nil)
36: 	t.Add("/api/plugins/:id/resources/*", nil)
37: 
38: 	return func(c *web.Context) {
39: 		c.Resp.Before(func(w web.ResponseWriter) { // if response has already been written, skip.
40: 			if w.Written() {
41: 				return
42: 			}
43: 
44: 			traceId := tracing.TraceIDFromContext(c.Req.Context(), false)
45: 			if traceId != "" {
46: 				w.Header().Set("grafana-trace-id", traceId)
47: 			}
48: 
49: 			_, _, resourceURLMatch := t.Match(c.Req.URL.Path)
50: 			resourceCachable := resourceURLMatch && allowCacheControl(c.Resp)
51: 			if !strings.HasPrefix(c.Req.URL.Path, "/public/plugins/") &&
52: 				!strings.HasPrefix(c.Req.URL.Path, "/avatar/") &&
53: 				!strings.HasPrefix(c.Req.URL.Path, "/api/datasources/proxy/") &&
54: 				!strings.HasPrefix(c.Req.URL.Path, "/api/reports/render/") &&
55: 				!strings.HasPrefix(c.Req.URL.Path, "/render/d-solo/") &&
56: 				(!strings.HasPrefix(c.Req.URL.Path, "/api/gnet/plugins") || !strings.Contains(c.Req.URL.Path, "/logos/")) && !resourceCachable {
57: 				addNoCacheHeaders(c.Resp)
58: 			}
59: 
60: 			// X-Allow-Embedding header is set for specific URLs that need to be embedded in an iframe regardless
61: 			// of the configured allow_embedding setting.
62: 			embeddingHeader := w.Header().Get("X-Allow-Embedding")
63: 			if !cfg.AllowEmbedding && embeddingHeader != "allow" {
64: 				addXFrameOptionsDenyHeader(w)
65: 			}
66: 			addSecurityHeaders(w, cfg)
67: 		})
68: 	}
69: }
70: 
71: // addSecurityHeaders adds HTTP(S) response headers that enable various security protections in the client's browser.
72: func addSecurityHeaders(w web.ResponseWriter, cfg *setting.Cfg) {
73: 	if cfg.StrictTransportSecurity {
74: 		strictHeaderValues := []string{fmt.Sprintf("max-age=%v", cfg.StrictTransportSecurityMaxAge)}
75: 		if cfg.StrictTransportSecurityPreload {
76: 			strictHeaderValues = append(strictHeaderValues, "preload")
77: 		}
78: 		if cfg.StrictTransportSecuritySubDomains {
79: 			strictHeaderValues = append(strictHeaderValues, "includeSubDomains")
80: 		}
81: 		w.Header().Set("Strict-Transport-Security", strings.Join(strictHeaderValues, "; "))
82: 	}
83: 
84: 	if cfg.ContentTypeProtectionHeader {
85: 		w.Header().Set("X-Content-Type-Options", "nosniff")
86: 	}
87: 
88: 	if cfg.XSSProtectionHeader {
89: 		w.Header().Set("X-XSS-Protection", "1; mode=block")
90: 	}
91: }
92: 
93: func addNoCacheHeaders(w web.ResponseWriter) {
94: 	w.Header().Set("Cache-Control", "no-store")
95: 	w.Header().Del("Pragma")
96: 	w.Header().Del("Expires")
97: }
98: 
99: func addXFrameOptionsDenyHeader(w web.ResponseWriter) {
100: 	w.Header().Set("X-Frame-Options", "deny")
101: }
102: 
103: func AddCustomResponseHeaders(cfg *setting.Cfg) web.Handler {
104: 	return func(c *web.Context) {
105: 		c.Resp.Before(func(w web.ResponseWriter) {
106: 			if w.Written() {
107: 				return
108: 			}
109: 
110: 			for header, value := range cfg.CustomResponseHeaders {
111: 				// do not override existing headers
112: 				if w.Header().Get(header) != "" {
113: 					continue
114: 				}
115: 				w.Header().Set(header, value)
116: 			}
117: 		})
118: 	}
119: }
120: 
121: func allowCacheControl(rw web.ResponseWriter) bool {
122: 	ccHeaderValues := rw.Header().Values("Cache-Control")
123: 
124: 	if len(ccHeaderValues) == 0 {
125: 		return false
126: 	}
127: 
128: 	foundPrivate := false
129: 	foundPublic := false
130: 	for _, val := range ccHeaderValues {
131: 		strings.Contains(val, "private")
132: 		if strings.Contains(val, "private") {
133: 			foundPrivate = true
134: 		}
135: 		if strings.Contains(val, "public") {
136: 			foundPublic = true
137: 		}
138: 	}
139: 
140: 	return foundPrivate && !foundPublic && rw.Header().Get("X-Grafana-Cache") != ""
141: }
