100: func (p permissionEvaluator) MutateScopes(ctx context.Context, mutate ScopeAttributeMutator) (Evaluator, error) {
101: 	ctx, span := tracer.Start(ctx, "accesscontrol.permissionEvaluatorMutateScopes")
102: 	defer span.End()
103: 
104: 	if p.Scopes == nil {
105: 		return EvalPermission(p.Action), nil
106: 	}
107: 
108: 	resolved := false
109: 	scopes := make([]string, 0, len(p.Scopes))
110: 	for _, scope := range p.Scopes {
111: 		mutated, err := mutate(ctx, scope)
112: 		if err != nil {
113: 			if errors.Is(err, ErrResolverNotFound) {
114: 				scopes = append(scopes, mutated...)
115: 				continue
116: 			}
117: 			return nil, err
118: 		}
119: 		resolved = true
120: 		scopes = append(scopes, mutated...)
121: 	}
122: 
123: 	if !resolved {
124: 		return nil, ErrResolverNotFound
125: 	}
126: 
127: 	return EvalPermission(p.Action, scopes...), nil
128: }
